import React from 'react';
import { useWebSocket } from './hooks/useWebSocket';
import DashboardOverview from './components/DashboardOverview';
import QueryAnalytics from './components/QueryAnalytics';
import ProductionScore from './components/ProductionScore';

function App() {
    const { data, isConnected } = useWebSocket('ws://localhost:8000/ws');

    return (
        <div className="min-h-screen bg-gray-950 text-gray-100 p-8 font-mono">
            {/* Header */}
            <header className="flex justify-between items-center mb-10 pb-6 border-b border-gray-800">
                <div>
                    <h1 className="text-3xl font-black tracking-tighter text-white">APEX <span className="text-emerald-500 font-light">Platform</span></h1>
                    <p className="text-gray-400 mt-1 text-sm tracking-widest uppercase">Autonomous Multi-Agent Control Plane</p>
                </div>
                <div className="flex items-center space-x-4">
                    <span className={`flex items-center text-sm font-bold uppercase tracking-wider ${isConnected ? 'text-emerald-400' : 'text-red-400'}`}>
                        <span className={`w-3 h-3 rounded-full mr-2 ${isConnected ? 'bg-emerald-400 animate-pulse' : 'bg-red-400'}`}></span>
                        {isConnected ? 'Telemetry Active' : 'Offline'}
                    </span>
                </div>
            </header>

            {/* Main Grid */}
            <main className="max-w-7xl mx-auto space-y-8">

                {/* Top KPI Cards (Agent 1, Agent 2) */}
                <DashboardOverview />

                {/* Middle Complex Metrics */}
                <div className="grid grid-cols-1 lg:grid-cols-3 gap-8 h-96">

                    {/* Agent 4: RL Query Intelligence Routing */}
                    <div className="lg:col-span-2">
                        {data ? <QueryAnalytics data={data} /> : <div className="animate-pulse bg-gray-800 rounded-xl h-full w-full"></div>}
                    </div>

                    {/* Agent 7: Production Readiness Cox Model */}
                    <div className="lg:col-span-1">
                        {data ? <ProductionScore data={data} /> : <div className="animate-pulse bg-gray-800 rounded-xl h-full w-full"></div>}
                    </div>

                </div>

                {/* Footer / Alert Ticker (Agent 5 Vision) */}
                <footer className="mt-12 p-4 bg-gray-900 rounded-xl border border-gray-800">
                    <h4 className="text-sm font-bold text-gray-500 uppercase tracking-widest mb-2">Live Alerts (Agent 5 Vision Monitor)</h4>
                    {data && data.alerts ? (
                        <ul className="space-y-2">
                            {data.alerts.map((alert: any) => (
                                <li key={alert.id} className="flex items-center text-sm">
                                    <span className="w-2 h-2 rounded-full bg-red-500 mr-3 animate-ping"></span>
                                    <span className="text-red-400 font-mono">{alert.msg}</span>
                                </li>
                            ))}
                        </ul>
                    ) : <p className="text-gray-600 text-sm font-mono">No anomalies detected.</p>}
                </footer>

            </main>
        </div>
    );
}

export default App;
